namespace sv_716fdc308a39462387be1fac0b9f6d8a.Services;

public enum Severity
{
    Info,
    Warning,
    Critical
}

public class Notification
{
    public Guid Id { get; init; } = Guid.NewGuid();
    public required string Title { get; init; }
    public required string Message { get; init; }
    public Severity Severity { get; init; }
    public bool IsRead { get; set; }
    public DateTime Timestamp { get; init; } = DateTime.UtcNow;
}

/// <summary>
/// Scoped per circuit. Holds notifications and notifies all subscribers on any mutation.
/// </summary>
public class NotificationHub
{
    private readonly List<Notification> _notifications = [];
    private readonly Lock _lock = new();

    public event Action? OnChange;

    public IReadOnlyList<Notification> Notifications
    {
        get
        {
            lock (_lock)
            {
                return _notifications.ToList();
            }
        }
    }

    public int GetUnreadCount()
    {
        lock (_lock)
        {
            return _notifications.Count(n => !n.IsRead);
        }
    }

    public void AddNotification(string title, string message, Severity severity = Severity.Info)
    {
        lock (_lock)
        {
            _notifications.Add(new Notification
            {
                Title = title,
                Message = message,
                Severity = severity
            });
        }
        OnChange?.Invoke();
    }

    public void MarkAsRead(Guid id)
    {
        lock (_lock)
        {
            var notification = _notifications.FirstOrDefault(n => n.Id == id);
            if (notification is not null)
                notification.IsRead = true;
        }
        OnChange?.Invoke();
    }

    public void MarkAllRead()
    {
        lock (_lock)
        {
            foreach (var n in _notifications)
                n.IsRead = true;
        }
        OnChange?.Invoke();
    }

    public void DismissNotification(Guid id)
    {
        lock (_lock)
        {
            _notifications.RemoveAll(n => n.Id == id);
        }
        OnChange?.Invoke();
    }
}

namespace sv_716fdc308a39462387be1fac0b9f6d8a.Services;

/// <summary>
/// Scoped service that adds a random notification every 15 seconds.
/// Start/Stop are called by the dashboard page component.
/// </summary>
public class SimulatorService : IAsyncDisposable
{
    private readonly NotificationHub _hub;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private Task? _runningTask;

    private static readonly string[] Titles =
    [
        "Server CPU spike",
        "Disk space low",
        "New user registered",
        "Deployment completed",
        "Cache miss rate high",
        "Backup finished",
        "SSL certificate expiring",
        "Memory usage warning",
        "Health check failed",
        "Rate limit exceeded"
    ];

    private static readonly string[] Messages =
    [
        "Detected unusual activity on the primary cluster.",
        "Threshold exceeded — review the monitoring dashboard.",
        "Action completed successfully, no issues found.",
        "Automated process triggered; review logs for details.",
        "Immediate attention may be required.",
        "Scheduled maintenance window approaching."
    ];

    public SimulatorService(NotificationHub hub)
    {
        _hub = hub;
    }

    public void Start()
    {
        if (_timer is not null) return;

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(15));
        _runningTask = RunAsync(_cts.Token);
    }

    public void Stop()
    {
        _cts?.Cancel();
        _timer?.Dispose();
        _timer = null;
    }

    private async Task RunAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                var severity = (Severity)Random.Shared.Next(0, 3);
                var title = Titles[Random.Shared.Next(Titles.Length)];
                var message = Messages[Random.Shared.Next(Messages.Length)];
                _hub.AddNotification(title, message, severity);
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose
        }
    }

    public async ValueTask DisposeAsync()
    {
        Stop();
        if (_runningTask is not null)
        {
            await _runningTask;
        }
        _cts?.Dispose();
    }
}

