@using sv_716fdc308a39462387be1fac0b9f6d8a.Services
@inject NotificationHub Hub
@inject NavigationManager Nav
@implements IDisposable

<button class="notification-bell" @onclick="GoToNotifications" title="Notifications">
    <span class="bell-icon">🔔</span>
    @if (_unreadCount > 0)
    {
        <span class="badge-count">@(_unreadCount > 99 ? "99+" : _unreadCount)</span>
    }
</button>

@code {
    private int _unreadCount;
    private Action? _handler;

    protected override void OnInitialized()
    {
        _unreadCount = Hub.GetUnreadCount();
        // Wrap in InvokeAsync because SimulatorService fires OnChange from a non-UI thread
        _handler = () => InvokeAsync(() =>
        {
            _unreadCount = Hub.GetUnreadCount();
            StateHasChanged();
        });
        Hub.OnChange += _handler;
    }

    private void GoToNotifications() => Nav.NavigateTo("/notifications");

    public void Dispose() => Hub.OnChange -= _handler;
}

