toolArgs.file_text:
@page "/notifications"
@rendermode InteractiveServer
@using sv_716fdc308a39462387be1fac0b9f6d8a.Services
@inject NotificationHub Hub
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h1>Notifications</h1>
    @if (Hub.GetUnreadCount() > 0)
    {
        <button class="btn btn-outline-primary" @onclick="MarkAllRead">Mark All Read</button>
    }
</div>

@if (!_grouped.Any())
{
    <p class="text-muted">No notifications.</p>
}
else
{
    @foreach (var group in _grouped)
    {
        <h4 class="mt-4">
            <span class="badge @SeverityBadgeClass(group.Key)">@group.Key</span>
        </h4>
        <ul class="list-group mb-3">
            @foreach (var n in group)
            {
                <li class="list-group-item d-flex justify-content-between align-items-start @(n.IsRead ? "" : "list-group-item-light fw-semibold")">
                    <div class="me-auto">
                        <div>@n.Title</div>
                        <small class="text-muted">@n.Message</small>
                        <br />
                        <small class="text-muted">@n.Timestamp.ToString("g")</small>
                    </div>
                    <div class="btn-group btn-group-sm ms-2">
                        @if (!n.IsRead)
                        {
                            <button class="btn btn-outline-success" @onclick="() => MarkRead(n.Id)">Mark Read</button>
                        }
                        <button class="btn btn-outline-danger" @onclick="() => Dismiss(n.Id)">Dismiss</button>
                    </div>
                </li>
            }
        </ul>
    }
}

@code {
    private IEnumerable<IGrouping<Severity, Notification>> _grouped = [];
    private Action? _handler;

    protected override void OnInitialized()
    {
        RefreshGrouped();
        _handler = () => InvokeAsync(() =>
        {
            RefreshGrouped();
            StateHasChanged();
        });
        Hub.OnChange += _handler;
    }

    private void RefreshGrouped()
    {
        _grouped = Hub.Notifications
            .OrderBy(n => n.Severity switch
            {
                Severity.Critical => 0,
                Severity.Warning => 1,
                _ => 2
            })
            .GroupBy(n => n.Severity);
    }

    private void MarkRead(Guid id) => Hub.MarkAsRead(id);
    private void MarkAllRead() => Hub.MarkAllRead();
    private void Dismiss(Guid id) => Hub.DismissNotification(id);

    private static string SeverityBadgeClass(Severity s) => s switch
    {
        Severity.Critical => "bg-danger",
        Severity.Warning => "bg-warning text-dark",
        _ => "bg-info text-dark"
    };

    public void Dispose() => Hub.OnChange -= _handler;
}

