toolArgs.file_text:
@using sv_716fdc308a39462387be1fac0b9f6d8a.Services
@inject NotificationHub Hub
@implements IDisposable

<div class="card">
    <div class="card-header fw-semibold">Recent Unread Notifications</div>
    <ul class="list-group list-group-flush">
        @if (!_recent.Any())
        {
            <li class="list-group-item text-muted">All caught up!</li>
        }
        else
        {
            @foreach (var n in _recent)
            {
                <li class="list-group-item d-flex justify-content-between align-items-start">
                    <div class="me-auto">
                        <span class="badge @SeverityBadgeClass(n.Severity) me-1">@n.Severity</span>
                        @n.Title
                        <br />
                        <small class="text-muted">@n.Message</small>
                    </div>
                    <button class="btn btn-sm btn-outline-danger" @onclick="() => Dismiss(n.Id)">Dismiss</button>
                </li>
            }
        }
    </ul>
</div>

@code {
    private List<Notification> _recent = [];
    private Action? _handler;

    protected override void OnInitialized()
    {
        RefreshRecent();
        _handler = () => InvokeAsync(() =>
        {
            RefreshRecent();
            StateHasChanged();
        });
        Hub.OnChange += _handler;
    }

    private void RefreshRecent()
    {
        _recent = Hub.Notifications
            .Where(n => !n.IsRead)
            .OrderByDescending(n => n.Timestamp)
            .Take(3)
            .ToList();
    }

    private void Dismiss(Guid id) => Hub.DismissNotification(id);

    private static string SeverityBadgeClass(Severity s) => s switch
    {
        Severity.Critical => "bg-danger",
        Severity.Warning => "bg-warning text-dark",
        _ => "bg-info text-dark"
    };

    public void Dispose() => Hub.OnChange -= _handler;
}

